import React from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import response from './response.json';

interface Meeting {
  title: string;
  time: string;
  location: string;
}

interface AgendaData {
  upcomingMeetings: Meeting[];
}

export default function Widget() {
  const agendaData = response.data as AgendaData;
  const { upcomingMeetings } = agendaData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 280, maxWidth: 380, bgcolor: '#303030' }} elevation={2}>
      <CardContent sx={{ p: 2 }}>
        <Stack spacing={1.5}>
          <Typography variant="h6" sx={{ color: '#FFC107', mb: 1 }}>
            Upcoming Meetings
          </Typography>
          {upcomingMeetings.map((meeting, index) => (
            <Box key={index} sx={{ bgcolor: '#424242', borderRadius: 1, p: 1.5 }}>
              <Typography variant="body1" sx={{ color: '#FFFFFF' }}>
                {meeting.title}
              </Typography>
              <Typography variant="body2" sx={{ color: '#B0BEC5' }}>
                {meeting.time} - {meeting.location}
              </Typography>
            </Box>
          ))}
        </Stack>
      </CardContent>
    </Card>
  );
}
